#include <bits/stdc++.h>
using namespace std;

const int N=5010,mod=1e9+7;

int n,m,k,w[N],mp[256];
char s[N][N];
long long sum[N][4];

int main(){
    srand(time(NULL));
    mp['A']=0;
    mp['T']=1;
    mp['G']=2;
    mp['C']=3;
    scanf("%d%d%d",&n,&m,&k);
    long long cnt=0;
    for(int i=1;i<=n;i++){
        scanf("%s",s[i]+1);
        w[i]=1ll*rand()*rand()%mod;
        cnt+=w[i];
        for(int j=1;j<=m;j++)
            sum[j][mp[s[i][j]]]+=w[i];
    }
    for(int i=1;i<=n;i++){
        long long tmp=0;
        for(int j=1;j<=m;j++)
            tmp+=sum[j][0]+sum[j][1]+sum[j][2]+sum[j][3]-sum[j][mp[s[i][j]]];
        if((cnt-w[i])*k==tmp){
            printf("%d",i);
            break;
        }
    }
    return 0;
}
